CREATE OR REPLACE FUNCTION fpa_lon_count_memno_disinct (adt_bdate timestamp(0),adt_edate timestamp(0),as_client_id char,as_type char) RETURNS bigint AS $body$
DECLARE

  li_count bigint;

BEGIN
--ฟังก์ชั่น หาคนที่มาใช้บริการระหว่างวันที่ 1 คนมีกี่สัญญาก้อตามนับ 1
 if trim(both as_type) = 'ALL' then
 --นับทั่งหมด
  select  count( distinct membership_no)
  into STRICT    li_count
  from    sc_lon_m_contract
  where (begining_of_contract between adt_bdate and adt_edate);
 elsif trim(both as_type) = 'BAL' then
-- นับตามยอดคงเหลือ จาก table หุ้นหนี้คงเหลือ
  select  count(distinct membership_no)
  into STRICT    li_count
  from    sc_rep_mem_share_loan_bal
  where (emer_balance + norm_balance > 0)
  and (client_id = as_client_id);
 elsif trim(both as_type) = 'BAE' then
-- นับตามยอดคงเหลือ จาก table หุ้นหนี้คงเหลือ Emer_contract
  select  count(distinct membership_no)
  into STRICT    li_count
  from    sc_rep_mem_share_loan_bal
        , sc_lon_m_rule
  where (sc_lon_m_rule.loan_type = sc_rep_mem_share_loan_bal.emer_loantype)
  and (emer_balance  > 0)
  and (client_id = as_client_id);
 elsif trim(both as_type) = 'BAN' then
-- นับตามยอดคงเหลือ จาก table หุ้นหนี้คงเหลือ Norm_contract
  select  count(distinct membership_no)
  into STRICT    li_count
  from    sc_rep_mem_share_loan_bal
        , sc_lon_m_rule
  where (sc_lon_m_rule.loan_type = sc_rep_mem_share_loan_bal.norm_loantype)
  and (norm_balance  > 0)
  and (client_id = as_client_id);
 elsif  trim(both as_type) = 'MEM' then
-- นับจำนวนสมาชิก
--ที่ สอ.นย. จะนับเป็นสมาชิกเมื่อมีหุ้นมากกว่า 0 เท่านั้น
  select  count(distinct membership_no)
  into STRICT    li_count
  from    sc_rep_mem_share_loan_bal
  where (share_balance > 0)
  and (client_id = as_client_id);
 else
   null;
 end if;

return  li_count;
exception when others then CALL spa_dberror('FPA_LON_COUNT_MEMNO_DISINCT');return null;
END;
$body$
LANGUAGE PLPGSQL
SECURITY DEFINER
;
